  // @scenario TS-UI-013 (covers BHV-312)
  // Known issue: Redo does not re-apply status change. The undo/redo state management
  // uses useReducer + useCallback, but after undo triggers a PAPI round-trip
  // (write to project setting, read back via useProjectSetting), the redo handler's
  // call to onApprovedItemsChange does not propagate the restored state back to the
  // toggle UI. The undo flow works correctly. This is tracked as a component bug.
  test.fixme('should redo status change', async ({ mainPage }) => {
    await openMatchedPairsInventory(mainPage);

    const frame = getInventoryFrame(mainPage);

    const inventoryList = frame.getByTestId('inventory-list');
    await expect(inventoryList).toBeVisible({ timeout: 15_000 });

    const firstDataRow = inventoryList.locator('table tbody tr').first();
    await firstDataRow.click();

    // Capture initial state of the approved toggle (position 0: circle-check)
    const approvedToggle = firstDataRow.locator('[role="radio"]').nth(0);
    const initialState = await approvedToggle.getAttribute('data-state');

    // Click the approved toggle to change its state
    await approvedToggle.click();
    await mainPage.waitForTimeout(500);

    // Capture the post-click state (it toggled from initial)
    const postClickState = await approvedToggle.getAttribute('data-state');
    // Verify the click actually changed something
    expect(postClickState).not.toBe(initialState);

    // Undo: should revert to initial state
    const undoButton = frame.getByRole('button', { name: /Undo/i });
    await undoButton.click();
    // Wait for undo to take effect (PAPI round-trip + React re-render)
    await expect(approvedToggle).toHaveAttribute('data-state', initialState ?? 'off', {
      timeout: 10_000,
    });

    // Wait for redo button to become enabled (React must re-render with updated redoStack)
    const redoButton = frame.getByRole('button', { name: /Redo/i });
    await expect(redoButton).toBeEnabled({ timeout: 5_000 });

    // Redo: should restore the post-click state
    await redoButton.click();
    await expect(approvedToggle).toHaveAttribute('data-state', postClickState ?? 'on', {
      timeout: 10_000,
    });
  });

